1	export type Cell = [number, number];
2	
3	function isNeighbor(cell: Cell, other: Cell): boolean {
4	  const [x, y] = cell;
5	  const [ox, oy] = other;
6	  const isSameCell = ox === x && oy === y;
7	  return !isSameCell && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
8	}
9	
10	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
11	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
12	}
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  return liveCells.filter((cell) => {
16	    const neighbors = countLiveNeighbors(cell, liveCells);
17	    return neighbors === 2 || neighbors === 3;
18	  });
19	}
